sql:
SELECT SUM(revenue) AS total_revenue
FROM product_performance
WHERE seller_id = 0;

SELECT product_id, SUM(sales) AS total_sales
FROM product_performance
GROUP BY product_id;

SELECT product_id, revenue
FROM product_performance
WHERE revenue = (
    SELECT MAX(revenue)
    FROM product_performance
);

SELECT sales
FROM product_performance
WHERE sales > 50;

SELECT price
FROM amazon_data
WHERE average_rating > 4.0;

